// components/AIChat.jsx
import React, { useState, useRef, useEffect } from 'react';
import { CHAT_REPLIES } from '../data/mockData';

export default function AIChat() {
  const [open, setOpen]       = useState(false);
  const [input, setInput]     = useState('');
  const [messages, setMessages] = useState([
    { from:'bot', text:'Namaste! 🙏 I\'m Krishi AI. Ask me about crop prices, weather alerts, or transport.' },
    { from:'bot', text:'Try: "wheat price", "weather today", or "book transport".' },
  ]);
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:'smooth' }); }, [messages]);

  function send() {
    const msg = input.trim();
    if (!msg) return;
    setMessages(m => [...m, { from:'user', text: msg }]);
    setInput('');
    setTimeout(() => {
      const lower = msg.toLowerCase();
      let reply = CHAT_REPLIES.default;
      for (const key of Object.keys(CHAT_REPLIES)) {
        if (lower.includes(key)) { reply = CHAT_REPLIES[key]; break; }
      }
      setMessages(m => [...m, { from:'bot', text: reply }]);
    }, 600);
  }

  return (
    <>
      {/* FAB */}
      <button
        onClick={() => setOpen(o => !o)}
        style={{
          position:'fixed', bottom:32, right:32, zIndex:900,
          width:56, height:56, borderRadius:'50%',
          background:'var(--green)', color:'white', border:'none',
          fontSize:24, boxShadow:'0 8px 24px rgba(45,106,47,0.4)',
          transition:'all 0.2s', cursor:'pointer',
        }}
        onMouseEnter={e => { e.target.style.transform='scale(1.1)'; }}
        onMouseLeave={e => { e.target.style.transform='scale(1)'; }}
      >🤖</button>

      {/* Panel */}
      {open && (
        <div style={{
          position:'fixed', bottom:100, right:32, zIndex:900,
          width:336, background:'white', borderRadius:20,
          boxShadow:'0 16px 60px rgba(0,0,0,0.15)',
          border:'1px solid var(--border)',
          display:'flex', flexDirection:'column', overflow:'hidden',
          animation:'fadeUp 0.28s ease',
        }}>
          {/* Header */}
          <div style={{
            background:'var(--green)', color:'white',
            padding:'14px 18px', display:'flex', alignItems:'center', gap:12,
          }}>
            <div style={{
              width:36, height:36, borderRadius:'50%',
              background:'rgba(255,255,255,0.2)',
              display:'flex', alignItems:'center', justifyContent:'center', fontSize:18,
            }}>🌿</div>
            <div>
              <div style={{ fontWeight:700, fontSize:15 }}>Krishi AI</div>
              <div style={{ fontSize:12, opacity:.7 }}>
                <span className="badge-dot" style={{ marginRight:5 }}></span>
                Online — Powered by Gemini
              </div>
            </div>
          </div>

          {/* Messages */}
          <div style={{
            padding:'16px', height:230, overflowY:'auto',
            display:'flex', flexDirection:'column', gap:10,
          }}>
            {messages.map((m, i) => (
              <div key={i} style={{ alignSelf: m.from === 'bot' ? 'flex-start' : 'flex-end', maxWidth:'88%' }}>
                <div style={{
                  padding:'9px 13px', borderRadius:14, fontSize:13, lineHeight:1.5,
                  background: m.from === 'bot' ? 'var(--bg)' : 'var(--green)',
                  color: m.from === 'bot' ? 'var(--text)' : 'white',
                  borderBottomLeftRadius:  m.from === 'bot' ? 4 : 14,
                  borderBottomRightRadius: m.from === 'user' ? 4 : 14,
                }}>{m.text}</div>
              </div>
            ))}
            <div ref={bottomRef} />
          </div>

          {/* Input */}
          <div style={{
            display:'flex', gap:8, padding:'10px 14px',
            borderTop:'1px solid var(--border)',
          }}>
            <input
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && send()}
              placeholder="Ask about prices, weather..."
              style={{
                flex:1, padding:'9px 13px',
                border:'1.5px solid var(--border)', borderRadius:10,
                fontSize:13, outline:'none', fontFamily:'var(--font-body)',
              }}
            />
            <button
              onClick={send}
              style={{
                background:'var(--green)', color:'white',
                border:'none', width:36, height:36,
                borderRadius:8, fontSize:16, cursor:'pointer',
              }}
            >➤</button>
          </div>
        </div>
      )}
    </>
  );
}
